from opentelemetry.sdk.trace import TracerProvider
from opentelemetry.sdk.trace.sampling import (
    ParentBased,
    TraceIdRatioBased,
    ALWAYS_ON,
    ALWAYS_OFF,
    Decision,
    SamplingResult,
    StaticSampler,
)
from opentelemetry.trace import SpanKind
from opentelemetry import context as ctx_api


class ErrorAwareSampler:
    """
    Always sample traces that already contain an error attribute.
    Fall back to 10% ratio sampling for clean traces.
    """

    def __init__(self, base_ratio: float = 0.10):
        self._ratio_sampler = TraceIdRatioBased(base_ratio)

    def should_sample(self, parent_context, trace_id, name, kind, attributes, links):
        # Always sample if this span carries an error flag
        if attributes and attributes.get("error") is True:
            return SamplingResult(Decision.RECORD_AND_SAMPLE)
        # Always sample policy_check spans (compliance requirement)
        if attributes and attributes.get("action_type") == "policy_check":
            return SamplingResult(Decision.RECORD_AND_SAMPLE)
        return self._ratio_sampler.should_sample(
            parent_context, trace_id, name, kind, attributes, links
        )

    @property
    def description(self) -> str:
        return "ErrorAwareSampler(error=always, others=10%)"


# Wire it up: ParentBased respects parent sampling decision
sampler = ParentBased(root=ErrorAwareSampler(base_ratio=0.10))
provider = TracerProvider(sampler=sampler)
